          {
                    "regex": "for\\s+.*\\s+in",
                    "issue": "Efficiency: Loop 'for-in' detectado em TS. Verifique se 'for-of' ou métodos funcionais são mais eficientes PhD.",
                    "severity": "low"
          },
          {
                    "regex": "Array\\([1-9][0-9]{4,}\\)",
                    "issue": "Allocation: Alocação de array gigante detectada. Risco de GC pressure PhD.",
                    "severity": "medium"
          },
          {
                    "regex": "while\\s*\\(\\s*true\\s*\\)",
                    "issue": "Complexity: Loop infinito detectado. Garanta que haja sinal de cancelamento PhD.",
                    "severity": "medium"
          }
]
            )
        )
    }

    fun performAudit() {
        println("☕ [${name}] Starting fleet-wide audit via Hub PhD...")
    }

    fun reasonAboutObjective(objective: String, file: String, context: String) {
        println("☕ [${name}] Delegating reasoning for '${objective}' to Hub...")
